app.get('/webhook', (req, res) => {
  const mode = req.query['hub.mode'];
  const token = req.query['hub.verify_token'];
  const challenge = req.query['hub.challenge'];
  if (mode === 'subscribe' && token === VERIFY_TOKEN) {
    res.status(200).send(challenge);
  } else {
    res.sendStatus(403);
  }
});

app.post('/webhook', async (req, res) => {
  const body = req.body;
  if (body.object === 'whatsapp_business_account') {
    const entry = body.entry?.[0];
    const changes = entry?.changes?.[0];
    const message = changes?.value?.messages?.[0];
    if (message) {
      const from = message.from;
      const text = message?.text?.body || '';
      console.log(`Message from ${from}: ${text}`);

      const match = projects.find(p => text.includes(p.keyword));
      const reply = match
        ? match.reply
        : "\u0532\u0561\u179c\u056b \u563a\u0561\u056c\u578d\u057d\u057f RED Invest Group \ud83d\udc4b\n\u0531\u056c \u0561\u057c\u0561\u057b\u056b\u056f \u056f\u0561\u057a\u0561\u056f\u0581\u056b\u0569\u0561\u0576 \u0570\u0561\u0574\u0561\u0580 \u057d\u0565\u063a\u0574\u0565\u0584 \u0561\u0575\u057d\u057f\u0587\u0563 \ud83d\udc49 https://redinvest.am";

      await sendMessage(from, reply);
      await createBitrixLead(from, text);
    }
  }
  res.sendStatus(200);
});

async function sendMessage(to, text) {
  const fetch = (await import('node-fetch')).default;
  const response = await fetch(
    `https://graph.facebook.com/v22.0/${process.env.PHONE_NUMBER_ID}/messages`,
    {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.ACCESS_TOKEN}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        messaging_product: 'whatsapp',
        to: to,
        type: 'text',
        text: { body: text },
      }),
    }
  );
  const data = await response.json();
  console.log('Sent:', JSON.stringify(data));
}

async function createBitrixLead(phone, message) {
  const fetch = (await import('node-fetch')).default;
  const url = `${process.env.BITRIX_WEBHOOK}crm.lead.add.json`;
  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      fields: {
        TITLE: `WhatsApp Lead - ${phone}`,
        PHONE: [{ VALUE: phone, VALUE_TYPE: 'WORK' }],
        COMMENTS: `First message: ${message}`,
        SOURCE_ID: 'WEB',
      }
    }),
  });
  const data = await response.json();
  console.log('Bitrix lead:', JSON.stringify(data));
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
